const payload = $input.item.json.body || $input.item.json;
const assets = payload.assets || [];
const zipAsset = assets.find(a => a.name && a.name.endsWith('.zip'));

if (!zipAsset) {
  return [{ json: { error: 'No .zip asset found in release payload', raw: payload } }];
}

return [{
  json: {
    release_tag: payload.tag_name || 'v1.0.0',
    zip_url: zipAsset.browser_download_url,
    brand_id: payload.brand_id || 'phonk_pipeline',
    timestamp: new Date().toISOString()
  }
}];

const fs = require('fs');
const batchDir = `/data/videos/batch_${$input.item.json.release_tag}`;
let metadata = [];

try {
  const rawMeta = fs.readFileSync(`${batchDir}/metadata.json`, 'utf8');
  metadata = JSON.parse(rawMeta);
} catch (e) {
  // Fallback scan of wav files if metadata.json not found
  const files = fs.readdirSync(batchDir).filter(f => f.endsWith('.wav'));
  metadata = files.map((f, i) => ({
    slug: f.replace('.wav', ''),
    brand_id: $input.item.json.brand_id,
    bpm: 155,
    audio_path: `${batchDir}/${f}`,
    cover_path: fs.existsSync(`${batchDir}/covers/${f.replace('.wav', '.png')}`) ? `${batchDir}/covers/${f.replace('.wav', '.png')}` : null
  }));
}

return metadata.map(item => ({
  json: {
    ...item,
    brand_id: item.brand_id || $input.item.json.brand_id || 'phonk_pipeline',
    batch_dir: batchDir
  }
}));

