const item = $input.item.json;
const brandId = item.brand_id || "phonk_pipeline";
const rawCaption = item.caption || "Check out this new release!";
const title = (item.slug || "New Track").replace(/_/g, ' ').toUpperCase();

const brandsConfig = {
  phonk_pipeline: { core: "#phonk #phonkmusic #gymphonk #driftphonk #phonkbeat", instagram: "#gymmotivation #carphonk #bodybuilding", youtube: "#shorts #shortvideo #phonk2026", tiktok: "#fyp #viral #phonk #gymtok #cartok" },
  publixion: { core: "#publixion #publishing #contentcreator #growth", linkedin: "#DigitalPublishing #MediaGrowth #ContentStrategy" },
  myfitnessleap: { core: "#fitness #health #workout #gym #fitnessmotivation", tiktok: "#gymtok #fitnesstok #fyp" },
  neurostackos: { core: "#nootropics #biohacking #neuroscience #focus", linkedin: "#Biohacking #Neuroscience #CognitivePerformance" }
};

const tags = brandsConfig[brandId] || brandsConfig.phonk_pipeline;

return {
  json: {
    ...item,
    video_path: `${item.batch_dir}/${item.slug}.mp4`,
    normalized_captions: {
      youtube: `${title} | ${tags.youtube}\n\n${rawCaption}\n\n${tags.core}`,
      instagram: `🔥 ${title}\n${rawCaption}\n.\n.\n.\n.\n.\n${tags.core} ${tags.instagram || ''}`,
      tiktok: `⚡ ${title} ⚡\n${rawCaption}\n\n${tags.core} ${tags.tiktok || ''}`,
      facebook: `${title} - ${rawCaption}\n\n${tags.core}`,
      linkedin: `${title}\n\n${rawCaption}\n\n${tags.linkedin || tags.core}`
    }
  }
};
